import React, { useState } from 'react';
import Select from 'react-select';

const EditOrder = ({ order, handleUpdate, handleCancel, vendors, locations, materials }) => {
  const [editedOrder, setEditedOrder] = useState({ ...order });

  console.log(editedOrder);
  console.log(locations);
  console.log(materials);


  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setEditedOrder((prevorder) => ({
      ...prevorder,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleUpdate(editedOrder);
    resetForm();
  };

  const findVendorById = (vendorId) => {
    return vendors.find((vendor) => vendor.vendorid === vendorId);
  };

  const resetForm = () => {
    setEditedOrder({
      // Reset the fields as needed for the order
      // Example:
      name: '',
      description: '',
      prmatcost: '',
      prlabcost: '',
      sale: '',
      realmatcost: '',
      reallabcost: '',
      totalcost: '',
      // Add other fields here
    });
  };

  return (
    <div className="container">
      <h2 className="heading">Edit order</h2>
      <form className="form" onSubmit={handleSubmit}>
        <div className='form-row'>
          <div className='form-group'>
            <label>
              Location:
              <select name="location_id" value={editedOrder.location_id} onChange={handleInputChange} required>
                <option value="">Select a location</option>
                {locations.map((location) => (
                  <option key={location.id} value={location.id}>
                    {location.locationname}
                  </option>
                ))}
              </select>
            </label>
          </div>
          <div className='form-group'>
            <label>
              Material Id:
              <input
                type="text"
                name="material_id"
                value={editedOrder.material_id}
              />
            </label>
          </div>
          <div className='form-group'>
            <label>Material Name:</label>
            <input type="text" name="materialname" value={materials.find(mat => mat.matid === editedOrder.material_id)?.name} readOnly required />
          </div>
          <div className='form-group'>
            <label>
              Order Quantity:
              <input
                type="number"
                name="quantity"
                value={editedOrder.quantity}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className="form-group">
            <label>
              Vendor:
              <Select // Use Select component for vendors dropdown
                options={vendors.map(vendor => ({ value: vendor.vendorid, label: vendor.name }))}
                defaultValue={findVendorById(editedOrder.vendor_id)} // Preselect the vendor
                onChange={selectedOption => handleInputChange(selectedOption)}
              />
            </label>
          </div>

          <button type="submit">Edit order</button>
          <button type="button" className="add_btn" onClick={handleCancel}>
            Cancel
          </button>
        </div>
      </form>

    </div>
  );
};

export default EditOrder;
